challenges.description:
Slang interfaces let you write generic shaders that work over any type satisfying the interface contract. The Slang code below defines an IMaterial interface and two implementations. In GLSL, you must emulate this with a uniform integer selector and manual branching.

Slang to port:
```slang
interface IMaterial {
    float3 shade(float3 normal, float3 lightDir);
};

struct LambertMaterial : IMaterial {
    float3 albedo;
    float3 shade(float3 normal, float3 lightDir) {
        return albedo * max(dot(normal, lightDir), 0.0);
    }
};

struct EmissiveMaterial : IMaterial {
    float3 emission;
    float3 shade(float3 normal, float3 lightDir) {
        return emission;
    }
};

// Generic entry point — works for any IMaterial
[shader("fragment")]
float4 main<M : IMaterial>(M material, float3 normal : TEXCOORD0) : SV_Target {
    float3 light = normalize(float3(0.5, 1.0, 0.3));
    return float4(material.shade(normal, light), 1.0);
}
```

In GLSL, represent the material type with `uniform int u_materialType` (0 = Lambert, 1 = Emissive) and hardcode the two material parameter sets.

challenges.template:
uniform int   u_materialType;
uniform vec3  u_albedo;
uniform vec3  u_emission;
uniform vec2  u_resolution;
out vec4 fragColor;

vec3 shadeLambert(vec3 albedo, vec3 normal, vec3 lightDir) {
    return albedo * max(dot(normal, lightDir), 0.0);
}

vec3 shadeEmissive(vec3 emission) {
    return emission;
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;
    // Fake a normal from UV for demo purposes
    vec3 normal   = normalize(vec3(uv * 2.0 - 1.0, 1.0));
    vec3 lightDir = normalize(vec3(0.5, 1.0, 0.3));

    vec3 col;
    // Branch on u_materialType: 0 = Lambert, 1 = Emissive
    /* ??? */

    fragColor = vec4(col, 1.0);
}

challenges.solution:
uniform int   u_materialType;
uniform vec3  u_albedo;
uniform vec3  u_emission;
uniform vec2  u_resolution;
out vec4 fragColor;

vec3 shadeLambert(vec3 albedo, vec3 normal, vec3 lightDir) {
    return albedo * max(dot(normal, lightDir), 0.0);
}

vec3 shadeEmissive(vec3 emission) {
    return emission;
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;
    vec3 normal   = normalize(vec3(uv * 2.0 - 1.0, 1.0));
    vec3 lightDir = normalize(vec3(0.5, 1.0, 0.3));

    vec3 col;
    if (u_materialType == 0) {
        col = shadeLambert(u_albedo, normal, lightDir);
    } else {
        col = shadeEmissive(u_emission);
    }

    fragColor = vec4(col, 1.0);
}

hlsl.code:
cbuffer Params : register(b0) {
    int   u_materialType;
    float3 u_albedo;
    float3 u_emission;
};

float3 shadeLambert(float3 albedo, float3 n, float3 l) {
    return albedo * max(dot(n, l), 0.0);
}
float3 shadeEmissive(float3 emission) { return emission; }

float4 main(float3 normal : TEXCOORD0) : SV_Target {
    float3 light = normalize(float3(0.5, 1.0, 0.3));
    float3 col;
    if (u_materialType == 0) col = shadeLambert(u_albedo, normal, light);
    else                      col = shadeEmissive(u_emission);
    return float4(col, 1.0);
}

slang.code:
interface IMaterial {
    float3 shade(float3 normal, float3 lightDir);
};

struct LambertMaterial : IMaterial {
    float3 albedo;
    float3 shade(float3 normal, float3 lightDir) {
        return albedo * max(dot(normal, lightDir), 0.0);
    }
};

struct EmissiveMaterial : IMaterial {
    float3 emission;
    float3 shade(float3 normal, float3 lightDir) { return emission; }
};

[shader("fragment")]
float4 main<M : IMaterial>(M material, float3 normal : TEXCOORD0) : SV_Target {
    float3 light = normalize(float3(0.5, 1.0, 0.3));
    return float4(material.shade(normal, light), 1.0);
}

challenges.description:
Slang's ParameterBlock bundles related resources (constants + textures + samplers) into a single type-safe binding. Port the Slang shader below to GLSL ES 3.0, splitting the ParameterBlock into a UBO + individual sampler uniforms.

Slang to port:
```slang
struct SceneParams {
    float4x4 viewProj;
    float3   sunDirection;
    float    exposure;
    Texture2D        skyTex;
    SamplerState     skySampler;
};

uniform ParameterBlock<SceneParams> gScene;

[shader("fragment")]
float4 main(float2 uv : TEXCOORD0) : SV_Target {
    float3 dir = normalize(float3(uv * 2.0 - 1.0, 1.0));
    float3 sky = gScene.skyTex.Sample(gScene.skySampler, uv).rgb;
    float  sun = max(dot(dir, gScene.sunDirection), 0.0);
    return float4(sky * gScene.exposure + float3(sun), 1.0);
}
```

