challenges.solution:
layout(std140) uniform SceneParams {
    mat4  viewProj;
    vec3  sunDirection;
    float exposure;
};

uniform sampler2D u_skyTex;
uniform vec2      u_resolution;

out vec4 fragColor;

void main() {
    vec2 uv  = gl_FragCoord.xy / u_resolution;
    vec3 dir = normalize(vec3(uv * 2.0 - 1.0, 1.0));
    vec3 sky = texture(u_skyTex, uv).rgb;
    float sun = max(dot(dir, sunDirection), 0.0);
    vec3 col = sky * exposure + vec3(sun);
    fragColor = vec4(col, 1.0);
}

hlsl.code:
cbuffer SceneParams : register(b0) {
    float4x4 viewProj;
    float3   sunDirection;
    float    exposure;
};
Texture2D    g_skyTex    : register(t0);
SamplerState g_skySampler : register(s0);

float4 main(float2 uv : TEXCOORD0) : SV_Target {
    float3 dir = normalize(float3(uv * 2.0 - 1.0, 1.0));
    float3 sky = g_skyTex.Sample(g_skySampler, uv).rgb;
    float  sun = max(dot(dir, sunDirection), 0.0);
    return float4(sky * exposure + float3(sun, sun, sun), 1.0);
}

slang.code:
struct SceneParams {
    float4x4     viewProj;
    float3       sunDirection;
    float        exposure;
    Texture2D    skyTex;
    SamplerState skySampler;
};

uniform ParameterBlock<SceneParams> gScene;

[shader("fragment")]
float4 main(float2 uv : TEXCOORD0) : SV_Target {
    float3 dir = normalize(float3(uv * 2.0 - 1.0, 1.0));
    float3 sky = gScene.skyTex.Sample(gScene.skySampler, uv).rgb;
    float  sun = max(dot(dir, gScene.sunDirection), 0.0);
    return float4(sky * gScene.exposure + float3(sun, sun, sun), 1.0);
}

challenges.description:
Slang can automatically differentiate functions with respect to their inputs using the [Differentiable] attribute. This is used in neural rendering and gradient-based optimization. GLSL has no auto-diff; you must implement the derivative manually.

Slang differentiable function:
```slang
[Differentiable]
float sigmoid(float x) {
    return 1.0 / (1.0 + exp(-x));
}

// Auto-generated by Slang: derivative of sigmoid
// d/dx sigmoid(x) = sigmoid(x) * (1 - sigmoid(x))

[shader("fragment")]
float4 main(float2 uv : TEXCOORD0) : SV_Target {
    float x        = uv.x * 6.0 - 3.0;  // map [0,1] to [-3,3]
    float s        = sigmoid(x);
    // fwd-mode derivative with respect to x (dx = 1.0)
    float dsdx     = __fwd_diff(sigmoid)(diffPair(x, 1.0)).d;
    // visualize: red = sigmoid, green = derivative
    return float4(s, dsdx, 0.0, 1.0);
}
```

In GLSL, implement sigmoid() and its analytic derivative ds_dx = s*(1-s) manually, then visualize them the same way.

