float sigmoid(float x) {
    return 1.0 / (1.0 + exp(-x));
}
float sigmoidDerivative(float x) {
    float s = sigmoid(x);
    return s * (1.0 - s);
}

float4 main(float2 uv : TEXCOORD0) : SV_Target {
    float x    = uv.x * 6.0 - 3.0;
    float s    = sigmoid(x);
    float dsdx = sigmoidDerivative(x);
    return float4(s, dsdx, 0.0, 1.0);
}

